import { useState, useEffect } from 'react';

export default function ProductModal({ open, product, onClose, onSave }) {
  const [form, setForm] = useState({ title: '', category: '', description: '', price: '', stock: '' });

  useEffect(() => {
    if (product) setForm(product);
    else setForm({ title: '', category: '', description: '', price: '', stock: '' });
  }, [product]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const url = product 
      ? `http://localhost:3001/api/products/${product.id}` 
      : 'http://localhost:3001/api/products';
    const method = product ? 'PATCH' : 'POST';

    await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: form.title,
        category: form.category,
        description: form.description,
        price: Number(form.price),
        stock: Number(form.stock)
      })
    });
    onSave();
    onClose();
  };

  if (!open) return null;

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ background: 'white', padding: '30px', borderRadius: '12px', width: '400px' }}>
        <h2>{product ? 'Редактировать' : 'Новая позиция'}</h2>
        <form onSubmit={handleSubmit}>
          <input placeholder="Название" value={form.title} onChange={e => setForm({...form, title: e.target.value})} required style={{ width: '100%', margin: '8px 0', padding: '8px' }} />
          <input placeholder="Категория" value={form.category} onChange={e => setForm({...form, category: e.target.value})} required style={{ width: '100%', margin: '8px 0', padding: '8px' }} />
          <textarea placeholder="Описание" value={form.description} onChange={e => setForm({...form, description: e.target.value})} required style={{ width: '100%', margin: '8px 0', padding: '8px' }} />
          <input type="number" placeholder="Цена" value={form.price} onChange={e => setForm({...form, price: e.target.value})} required style={{ width: '100%', margin: '8px 0', padding: '8px' }} />
          <input type="number" placeholder="Остаток" value={form.stock} onChange={e => setForm({...form, stock: e.target.value})} required style={{ width: '100%', margin: '8px 0', padding: '8px' }} />
          <div style={{ marginTop: '20px' }}>
            <button type="submit" className="btn">Сохранить</button>
            <button type="button" onClick={onClose} style={{ marginLeft: '10px' }}>Отмена</button>
          </div>
        </form>
      </div>
    </div>
  );
}
